// Smart casts K2 handles that the old front-end refused:
val status: Any = load()
if (status is Error || status is Timeout) {
    log(status.reason)      // common supertype members: OK in K2
}

val action: (() -> Unit)? = pick()
if (action != null) run(action)   // captured non-null flows into lambdas

fun describe(response: Response) = when (response) {
    is Success if response.body.isEmpty() -> "empty payload"
    is Success                            -> "ok: ${response.body.size}"
    is Failure if response.retryable      -> "will retry"
    is Failure                            -> "gave up"
}

context(tx: Transaction, log: Logger)
fun transfer(from: Account, to: Account, amount: Money) {
    log.info("transfer $amount")
    tx.execute { ... }
}

